import httpx

async def fetch_user(id: int):
    try:
        async with httpx.AsyncClient() as client:
            res = await client.get(f"/api/users/{id}")
            res.raise_for_status()
            return res.json()
    except httpx.HTTPStatusError as e:
        print(f"Failed: {e}")
        return None

